/**
 * @file utils/ai-performance-monitor.js
 * @description This module initializes a performance monitor specifically for First Contentful Paint (FCP).
 * It uses the Performance Observer API to track FCP and logs the result to the console,
 * providing a simple AI-like assessment and recommendations based on common FCP thresholds.
 *
 * FCP is a crucial user-centric metric for measuring perceived load speed because it marks the first point
 * in the page load timeline where the user can see anything on the screen.
 */

/**
 * Initializes the First Contentful Paint (FCP) performance monitor.
 * It observes 'paint' performance entries and logs the FCP value along with an AI-like assessment.
 */
function initFCPMonitor() {
  if (!window.PerformanceObserver || !window.performance) {
    console.warn('PerformanceObserver or performance API not supported. FCP monitoring disabled.');
    return;
  }

  const observer = new PerformanceObserver((entryList) => {
    for (const entry of entryList.getEntries()) {
      if (entry.name === 'first-contentful-paint') {
        const fcpValue = entry.startTime; // FCP is typically measured in milliseconds

        console.groupCollapsed(`🚀 AI Performance Monitor: First Contentful Paint (FCP)`);
        console.log(`FCP Value: ${fcpValue.toFixed(2)} ms`);

        let assessment = 'Excellent!';
        let recommendation = 'Great job! Your FCP is very fast, ensuring a quick visual response for users.';
        let color = 'color: green; font-weight: bold;';

        if (fcpValue > 3000) { // Over 3 seconds
          assessment = 'Poor!';
          recommendation = 'Your FCP is quite slow. Focus on critical rendering path optimization, ' +
                           'reducing server response time, eliminating render-blocking resources (CSS/JS), ' +
                           'and optimizing image delivery.';
          color = 'color: red; font-weight: bold;';
        } else if (fcpValue > 1800) { // Between 1.8 and 3 seconds
          assessment = 'Needs Improvement.';
          recommendation = 'Your FCP could be faster. Consider optimizing server response times, ' +
                           'reducing the size of your initial HTML payload, and deferring non-critical CSS/JS.';
          color = 'color: orange; font-weight: bold;';
        }

        console.log(`%cAI Assessment: ${assessment}`, color);
        console.log(`AI Recommendation: ${recommendation}`);
        console.groupEnd();

        // Disconnect after finding FCP as it's a one-time event
        observer.disconnect();
        return;
      }
    }
  });

  try {
    observer.observe({ type: 'paint', buffered: true });
  } catch (e) {
    console.error('Failed to observe paint entries for FCP:', e);
  }
}

// Automatically initialize the FCP monitor when the script loads
// or export it for explicit initialization.
// For this fix, we'll assume it should be initialized on load.
initFCPMonitor();

// If you prefer to explicitly call it, you can export it:
// export { initFCPMonitor };
```

